// ── Helper Functions ─────────────────────────────────────────────

export function getLessonContent(slug: string): LessonContent | undefined {
  return contentMap[slug];
}

export function hasLessonContent(slug: string): boolean {
  return slug in contentMap;
}

export function getAllContentSlugs(): string[] {
  return Object.keys(contentMap);
}

export function getContentCount(): number {
  return Object.keys(contentMap).length;
}

export function getModuleContentSlugs(moduleNumber: number): string[] {
  const modulePrefix = `lesson${moduleNumber}_`;
  return Object.keys(contentMap).filter((slug) => {
    const content = contentMap[slug];
    return content.sections.some((s) => s.id.includes(`m${moduleNumber}`));
  });
}
